import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{a as i,i as a,n as o,o as s,r as c,s as l,t as u}from"./chunks/javap.CpTN0-Ru.js";const d=JSON.parse(`{"title":"Consigli e Trucchetti per VS Code","description":"Informazioni utili e pratiche per renderti il lavoro più piacevole.","frontmatter":{"title":"Consigli e Trucchetti per VS Code","description":"Informazioni utili e pratiche per renderti il lavoro più piacevole.","authors":["dicedpixels"],"prev":{"text":"Generare le Sorgenti in VS Code","link":"./generating-sources"},"next":false,"files":[]},"headers":[],"relativePath":"it_it/develop/getting-started/vscode/tips-and-tricks.md","filePath":"translated/it_it/develop/getting-started/vscode/tips-and-tricks.md","lastUpdated":1771183440000}`);var f={name:`it_it/develop/getting-started/vscode/tips-and-tricks.md`};function p(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Consigli e Trucchetti per VS Code <a class="header-anchor" href="#h1" aria-label="Permalink to “Consigli e Trucchetti per VS Code”">​</a></h1><p>È importante sapere come navigare le fonti generate, così da poter fare debugging e comprendere il funzionamento di Minecraft dietro le quinte. Qui presentiamo alcune prassi comuni nell&#39;IDE.</p><h2 id="searching-for-a-minecraft-class" tabindex="-1">Cercare una classe di Minecraft <a class="header-anchor" href="#searching-for-a-minecraft-class" aria-label="Permalink to “Cercare una classe di Minecraft”">​</a></h2><p>Appena le sorgenti saranno state generate, dovresti poter cercare e visualizzare le classi di Minecraft.</p><h3 id="viewing-class-definitions" tabindex="-1">Visualizzare le definizioni delle classi <a class="header-anchor" href="#viewing-class-definitions" aria-label="Permalink to “Visualizzare le definizioni delle classi”">​</a></h3><p><strong>Quick Open</strong> (<kbd>Ctrl</kbd>+<kbd>P</kbd>): Scrivi <code>#</code> seguito dal nome della classe (es. <code>#Identifier</code>).</p><p><img src="/assets/develop/getting-started/vscode/quick-open.png" alt="Finestra Quick Open" loading="lazy"></p><p><strong>Go to Definition</strong> (<kbd>F12</kbd>): Dal codice sorgente, naviga alla definizione di una classe facendo <kbd>Ctrl</kbd> + clic sul nome, o cliccando col pulsante destro e selezionando &quot;Go to Definition&quot;.</p><p><img src="/assets/develop/getting-started/vscode/go-to-definition.png" alt="Go to Definition" loading="lazy"></p><h3 id="finding-references" tabindex="-1">Trovare i riferimenti <a class="header-anchor" href="#finding-references" aria-label="Permalink to “Trovare i riferimenti”">​</a></h3><p>Puoi elencare gli utilizzi e i riferimenti a una classe cliccando con il pulsante destro sul nome di una classe e selezionando <strong>Find All References</strong>.</p><p><img src="/assets/develop/getting-started/vscode/find-all-references.png" alt="Find All References" loading="lazy"></p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Se le funzioni citate non funzionassero come dovrebbero, probabilmente le sorgenti non sono allegate correttamente. Di solito basta ripulire la cache dell&#39;ambiente per risolvere il problema.</p><ul><li>Clicca il pulsante <strong>Show Java Status Menu</strong> nella barra di stato.</li></ul><p><img src="/assets/develop/getting-started/vscode/java-ready.png" alt="Mostra lo stato di Java" loading="lazy"></p><ul><li>Nel menu appena aperto, seleziona <strong>Clean Workspace Cache...</strong> e conferma l&#39;operazione.</li></ul><p><img src="/assets/develop/getting-started/vscode/clear-workspace.png" alt="Ripulisci ambiente di lavoro" loading="lazy"></p><ul><li>Chiudi e riapri il progetto.</li></ul></div><h2 id="viewing-bytecode" tabindex="-1">Mostrare il bytecode <a class="header-anchor" href="#viewing-bytecode" aria-label="Permalink to “Mostrare il bytecode”">​</a></h2><p>Visualizzare il bytecode è necessario se si scrivono mixin. Tuttavia, a Visual Studio Code manca il supporto per la visualizzazione di bytecode, e le poche estensioni che lo introducono potrebbero non funzionare.</p><p>In questo caso, potresti usare lo strumento <code>javap</code> incluso con Java per visualizzare il bytecode.</p><ul><li><p><strong>Trova il percorso del JAR di Minecraft:</strong></p><p>Apri la vista Explorer, espandi la sezione <strong>Java Projects</strong>. Espandi il nodo <strong>Reference Libraries</strong> nell&#39;albero del progetto e trova un JAR che abbia <code>minecraft-</code> nel nome. Clicca con il pulsante destro sul JAR e copiane il percorso completo.</p><p>Potrebbe essere qualcosa del genere:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:/project/.gradle/loom-cache/minecraftMaven/net/minecraft/minecraft-merged-503b555a3d/1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2/minecraft-merged-503b555a3d-1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2.jar</span></span></code></pre></div></li></ul><p><img src="/assets/develop/getting-started/vscode/copy-path.png" alt="Copia il percorso" loading="lazy"></p><ul><li><p><strong>Esegui <code>javap</code>:</strong></p><p>Puoi ora eseguire <code>javap</code> passandoci il percorso appena copiato come <code>cp</code> (&quot;class path&quot;, percorso della classe) e il nome completo qualificato della classe come ultimo argomento.</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">javap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> C:/project/.gradle/loom-cache/minecraftMaven/net/minecraft/minecraft-merged-503b555a3d/1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2/minecraft-merged-503b555a3d-1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2.jar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -private</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net.minecraft.util.Identifier</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Questo riporterà il bytecode nell&#39;output del terminale.</p></li></ul><p><img src="/assets/develop/getting-started/vscode/javap.png" alt="javap" loading="lazy"></p>`,20)]])}var m=r(f,[[`render`,p]]);export{d as __pageData,m as default};